
import React, { useState, useEffect } from "react";

import { CloseModal, OpenModal } from "../../../components/DialogHRM";
import {  SvgIcon_Cmpt, TextInput_Cmpt, SearchInput_Cmpt, DeleteAlert_Cmpt, DropDwnPicker_Cmpt } from "../../../components";

import { updStore, getStore, gen16CodeId, ObjectKeys, qryKClient, copyToClipboard, parseDate, parseDateMMDDYYYY, txtOrempty, compareJSON, fetchEncryptStream, qryStore } from "../../../stores/Utils";
import { array2objAddIds } from "../services/customer_fetch_service";


const Svg = SvgIcon_Cmpt();


const DeleteAlert = DeleteAlert_Cmpt();

const DropDwnPicker = DropDwnPicker_Cmpt();



const TextInput = TextInput_Cmpt();

const frmNm = "upd_school"

const frmNmAdd = "add_school"



const SchoolsDashboardView  = ({ tabs, active, updTab }) => {
	const [obs, set_obs] = useState(1);
	


	

	const openAddView =  () => {

		

		let modal_data = {};
		modal_data["zIndex"] = 450;
		modal_data["height"] = "80vh";
		// data['observeResize']=true;
		modal_data["props"] = { minHeight: "1vh", overlay: true };
		modal_data["content"] =  <AddItemView confirm={addItem} />
		OpenModal(modal_data);
	}
	
	
	useEffect(() => {
		let ffm = {...getStore(qryKClient())};
		let schoolHistory = ffm?.schoolHistory || {};
		if(Array.isArray(getStore(qryKClient())?.schoolHistory)){
			schoolHistory = array2objAddIds(schoolHistory);
		}
		ffm.schoolHistory = schoolHistory;
		updStore(qryKClient(), ffm);
	});
	
	
	const rmvItem = async (indX2)=>{
		let ffm = {...getStore(qryKClient())};
		let schoolHistory = ffm?.schoolHistory || {};
		delete schoolHistory[indX2];
		saveItm(schoolHistory);
	}

	const addItem  =  (v)  => {
		let ffm = {...getStore(qryKClient())};
		let schoolHistory = ffm?.schoolHistory || {};
		schoolHistory[gen16CodeId()] = v;
		saveItm(schoolHistory);
	};
	
	const updItem = (v, indX2)=>{
		let ffm = {...getStore(qryKClient())};
		let schoolHistory = ffm?.schoolHistory || {};
		schoolHistory[indX2] = v;
		saveItm(schoolHistory);
	}

	const saveItm = async (schoolHistory)=>{
		let ffm = {...getStore(qryKClient())};
		let bdyq2 = {...getStore(qryStore())?.upd_notary};
        bdyq2.params = {
            "clientNotaryId": ffm["clientNotaryId"]
		}
		bdyq2.data2update = {schoolHistory };	
		
		const res = fetchEncryptStream(bdyq2);
		const td = await res;

		if (td && !td.error) {
			ffm.schoolHistory = schoolHistory;
			updStore(qryKClient(), ffm);
			updStore(frmNmAdd, null);
			updStore(frmNm, null);
			set_obs(gen16CodeId());
		}
	}
	
	

	let list2Render = getStore(qryKClient())?.schoolHistory;



	return (
		<div>
			<div style={{paddingTop: 30}}/>

			<div className="_dsplFlx " >
				<div className="iMTYiw" style={{marginTop: "8px"}}>
					Escuelas 
				</div>
				
				

				<div className="flexSpace"/>
				<div className="iSTOvb kvXcCL"  style={{padding: "0 9px" , width: "160px"}}  onClick={openAddView}>
					Agregar
				</div>
			</div>

			<div  className="_dsplFlx spaceAround flxWrp "  style={{padding: 9 }}>

			{list2Render && ObjectKeys(list2Render).map((itm, indA)=> <ItemView 
					key={itm+"_school"}
					index={indA} 
					idKey={itm}
					itm={list2Render[itm]}
					updObs={set_obs}
					update={updItem}
					rmv={rmvItem}
				/>
			)}
			</div>
		</div>
          
	)
}







export default SchoolsDashboardView;














